class Solution:
    def canReach(self, arr, start):
        n = len(arr)
        seen = [False] * n
        def dfs(i):
            if i < 0 or i >= n or seen[i]:
                return False
            if arr[i] == 0:
                return True
            seen[i] = True
            return dfs(i + arr[i]) or dfs(i - arr[i])
        import sys
        sys.setrecursionlimit(200000)
        return dfs(start)

