class Solution:
    def canReach(self, arr, start):
        from collections import deque
        n = len(arr)
        seen = [False] * n
        q = deque([start])
        seen[start] = True
        while q:
            i = q.popleft()
            if arr[i] == 0:
                return True
            for j in (i + arr[i], i - arr[i]):
                if 0 <= j < n and not seen[j]:
                    seen[j] = True
                    q.append(j)
        return False

