var canReach = function(arr, start) {
    const n = arr.length;
    const seen = new Array(n).fill(false);
    const q = [start];
    seen[start] = true;
    let head = 0;
    while (head < q.length) {
        const i = q[head++];
        if (arr[i] === 0) return true;
        for (const j of [i + arr[i], i - arr[i]]) {
            if (j >= 0 && j < n && !seen[j]) {
                seen[j] = true;
                q.push(j);
            }
        }
    }
    return false;
};
